PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "role" varchar not null default 'admin');
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "pricing_rules" ("id" integer primary key autoincrement not null, "nama_promo" varchar not null, "tipe" varchar not null, "value" numeric not null, "syarat_minimal_durasi" integer, "syarat_tipe_durasi" varchar not null default 'jam', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "start_date" date, "end_date" date, "deleted_at" datetime);
CREATE TABLE IF NOT EXISTS "rentals" ("id" integer primary key autoincrement not null, "unit_id" integer not null, "nik" varchar not null, "nama" varchar not null, "alamat" text not null, "no_wa" varchar not null, "waktu_mulai" datetime not null, "waktu_selesai" datetime not null, "subtotal_harga" numeric not null, "potongan_diskon" numeric not null default '0', "kode_unik_pembayaran" integer, "grand_total" numeric not null, "status" varchar check ("status" in ('pending', 'paid', 'completed', 'cancelled')) not null default 'pending', "created_at" datetime, "updated_at" datetime, "metode_pembayaran" varchar not null default 'qris', "denda" integer not null default '0', "denda_payment_method" varchar, "denda_kerusakan" integer not null default '0', "catatan_kerusakan" varchar, foreign key("unit_id") references "units"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "value" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "units" ("id" integer primary key autoincrement not null, "seri" varchar not null, "imei" varchar, "memori" varchar, "warna" varchar, "kondisi" text, "harga_per_jam" numeric not null default ('0'), "harga_per_hari" numeric not null default ('0'), "is_active" tinyint(1) not null default ('1'), "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "kategori" varchar not null default 'iphone');
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "settings_key_unique" on "settings" ("key");
CREATE UNIQUE INDEX "units_imei_unique" on "units" ("imei");
COMMIT;
